"""
modules/regulatory_stress_framework.py — ProQuant Capital | Basel IV & CCAR Framework v9.0
==========================================================================================
Bankacılık sektörü için Sermaye Yeterlilik Oranı (CAR), Likidite Karşılama Oranı (LCR) 
ve CCAR Stres testi uyumluluk şablonları motoru.
Author: ProQuant Capital Compliance Unit | Version: 9.0.0
"""

class RegulatoryStressFramework:
    def __init__(self):
        self.min_car = 0.08 # Basel minimum 8%
        
    def calculate_car(self, tier1: float, tier2: float, rwa: float) -> float:
        """Capital Adequacy Ratio hesaplama."""
        if rwa <= 0: return float('inf')
        return (tier1 + tier2) / rwa
        
    def calculate_lcr(self, hqla: float, net_cash_outflow_30d: float) -> float:
        """Liquidity Coverage Ratio hesaplama."""
        if net_cash_outflow_30d <= 0: return float('inf')
        return hqla / net_cash_outflow_30d

